// CRC-32 Calculator
module RefModule(
  input signed [31:0] a,
  input signed [31:0] b,
  input [1:0] op,
  output reg signed [31:0] result
);always @(*) begin
    case(op)
      2'b00: result = a + b;
      2'b01: result = a - b;
      2'b10: result = a * b;
      2'b11: result = a / b;
    endcase
  end

endmodule
